    91→function computeCouponDiscount(coupon, packagePrice) {
    92→  if (!coupon) return 0;
    93→  const numericAmount = Number(String(coupon.amount || "").replace(/[^\d.]/g, "")) || 0;
    94→  if (coupon.amountType === "fixed") return Math.min(packagePrice, numericAmount);
    95→  return Math.min(packagePrice, Math.round((packagePrice * numericAmount) / 100));
