   105→async function validateCouponForPackage(code, selectedPackage) {
   106→  if (!code) return { coupon: null, discount: 0, subtotal: selectedPackage.price, total: Math.round(selectedPackage.price * 1.18) };
   107→
   108→  const coupon = await Coupon.findOne({ code: String(code).trim().toUpperCase() });
   109→  if (!coupon) {
   110→    const error = new Error("Coupon code not found.");
   111→    error.statusCode = 404;
   112→    throw error;
   113→  }
   114→
   115→  const expiryDate = couponExpiryDate(coupon);
   116→  if (expiryDate && expiryDate <= new Date() && ["Active", "Applied", "Not used"].includes(coupon.status)) {
   117→    coupon.status = "Expired";
   118→    await coupon.save();
   119→  }
   120→
   121→  if (!["Active", "Not used"].includes(coupon.status)) {
   122→    const error = new Error(`Coupon is ${coupon.status.toLowerCase()} and cannot be applied.`);
   123→    error.statusCode = 400;
   124→    throw error;
   125→  }
   126→
   127→  const discount = computeCouponDiscount(coupon, selectedPackage.price);
   128→  const subtotal = Math.max(0, selectedPackage.price - discount);
   129→  const total = Math.round(subtotal * 1.18);
   130→
   131→  return {
   132→    coupon,
   133→    discount,
   134→    subtotal,
   135→    total
   136→  };
   137→}
