const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || "";

function makeNetworkError(message) {
  const err = new Error(message);
  err.isNetworkError = true;
  return err;
}

async function request(path, options = {}) {
  const headers = {
    "Content-Type": "application/json",
    ...(options.headers || {})
  };

  let response;
  try {
    response = await fetch(`${API_BASE_URL}${path}`, { ...options, headers });
  } catch (fetchErr) {
    throw makeNetworkError("Backend unavailable — working in demo mode.");
  }

  // Proxy/gateway errors (502, 503, 504) mean the backend is down
  if (response.status === 502 || response.status === 503 || response.status === 504) {
    throw makeNetworkError("Backend unavailable — working in demo mode.");
  }

  const data = await response.json().catch(() => ({}));
  if (!response.ok) {
    throw new Error(data.message || "Something went wrong.");
  }
  return data;
}

export function apiPost(path, body, token) {
  return request(path, {
    method: "POST",
    body: JSON.stringify(body),
    headers: token ? { Authorization: `Bearer ${token}` } : {}
  });
}

export function apiGet(path, token) {
  return request(path, {
    headers: token ? { Authorization: `Bearer ${token}` } : {}
  });
}

export function apiPut(path, body, token) {
  return request(path, {
    method: "PUT",
    body: JSON.stringify(body),
    headers: token ? { Authorization: `Bearer ${token}` } : {}
  });
}

export function apiDelete(path, token) {
  return request(path, {
    method: "DELETE",
    headers: token ? { Authorization: `Bearer ${token}` } : {}
  });
}

