     1→import { useEffect, useMemo, useState } from "react";
     2→import { apiDelete, apiGet, apiPost, apiPut } from "../lib/api";
     3→
     4→export function useCrmRecords(type, fallback = []) {
     5→  const [records, setRecords] = useState(fallback);
     6→  const [loading, setLoading] = useState(true);
     7→  const [error, setError] = useState("");
     8→
     9→  useEffect(() => {
    10→    let alive = true;
    11→    apiGet(`/api/crm/${type}`)
    12→      .then((data) => {
    13→        if (!alive) return;
    14→        setRecords(data.length ? data : fallback);
    15→        setError("");
    16→      })
    17→      .catch((err) => {
    18→        if (!alive) return;
    19→        setRecords(fallback);
    20→        setError(err.message);
    21→      })
    22→      .finally(() => alive && setLoading(false));
    23→
    24→    return () => {
    25→      alive = false;
    26→    };
    27→  }, [type, fallback]);
    28→
    29→  const actions = useMemo(() => ({
    30→    async save(record) {
    31→      const hasMongoId = Boolean(record._id);
    32→      const saved = hasMongoId
    33→        ? await apiPut(`/api/crm/${type}/${record._id}`, record)
    34→        : await apiPost(`/api/crm/${type}`, record);
    35→
    36→      setRecords((current) => {
    37→        const exists = current.some((item) => item._id === saved._id || item.id === saved.id);
    38→        if (!exists) return [saved, ...current];
    39→        return current.map((item) => (item._id === saved._id || item.id === saved.id ? saved : item));
    40→      });
    41→      return saved;
    42→    },
    43→    async remove(record) {
    44→      if (record._id) await apiDelete(`/api/crm/${type}/${record._id}`);
    45→      setRecords((current) => current.filter((item) => item._id !== record._id && item.id !== record.id));
    46→    },
    47→    setRecords
    48→  }), [type]);
    49→
    50→  return { records, loading, error, ...actions };
    51→}
    52→

